'use client';

import React, { useEffect, useState } from 'react';
import MovieForm from '@/src/components/MovieForm';
import { Movie } from '@/src/types';

export default function MoviesPage() {
  const [movies, setMovies] = useState<Movie[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [editingMovie, setEditingMovie] = useState<Movie | null>(null);

  // Fetch all movies
  const fetchMovies = async () => {
    try {
      const res = await fetch('/api/movies');
      const data = await res.json();
      setMovies(data); // Adjust if your API returns { success: true, movie: [...] }
    } catch (err) {
      console.error('Failed to fetch movies', err);
    }
  };

  useEffect(() => {
    fetchMovies();
  }, []);

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold mb-4">Movie List</h1>

      {/* Add New Movie */}
      <button
        onClick={() => { setEditingMovie(null); setShowForm(true); }}
        className="px-4 py-2 bg-green-500 text-white rounded mb-4"
      >
        Add New Movie
      </button>

      {/* Movie List */}
      <div className="space-y-3">
        {movies.map(movie => (
          <div key={movie.id} className="p-4 bg-[#1a1a1a] flex justify-between items-center rounded">
            <div>
              <h2 className="text-white font-bold">{movie.title}</h2>
              <p className="text-sm text-gray-400">{movie.duration} | {movie.year}</p>
            </div>
            <button
              onClick={() => { setEditingMovie(movie); setShowForm(true); }}
              className="px-3 py-1 bg-yellow-500 text-black rounded"
            >
              Edit
            </button>
          </div>
        ))}
      </div>

      {/* Movie Form Modal */}
      {showForm && (
        <MovieForm
          movie={editingMovie || undefined}
          onClose={() => setShowForm(false)}
          onSuccess={() => {
            fetchMovies();   // refresh list after create/edit/delete
            setShowForm(false);
          }}
        />
      )}
    </div>
  );
}